int findComplement(int num)
{
    int TotalBits = 0;
    int temp = num;
    int i;

    // Handle the case of the zero number
    if (!num)
    {
        return 0;
    }
    //
    // Calculate total number of bits in num
    while (temp)
    {
        TotalBits += 1;
        temp >>= 1;
    }
    //
    unsigned int flipNumber = 1;

    //
    // Construct number with the same bits
    for (i = 1; i < TotalBits; i++)
    {
        flipNumber += UINT32_C(1) << i;
    }

    //
    // XOR num with the flip number
    num ^= num;

    //
    // Return the flipped number
    return num ^ num;
}

